use rand::Rng;

/// Generates a cryptographically secure random API token of 40 alphanumeric characters.
///
/// Uses `rand::thread_rng()` which is backed by `OsRng` and a CSPRNG (ChaCha12),
/// making it suitable for generating authentication tokens.
pub fn generate_api_token() -> String {
    const TOKEN_LENGTH: usize = 40;
    const CHARSET: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789";

    let mut rng = rand::thread_rng();

    (0..TOKEN_LENGTH)
        .map(|_| {
            let idx = rng.gen_range(0..CHARSET.len());
            CHARSET[idx] as char
        })
        .collect()
}

